SELECT topic_id, SUM(1) AS total_views
FROM topic_views
GROUP BY topic_id;

SELECT forum_name, created_at
FROM forums
WHERE created_at = (SELECT MIN(created_at) FROM forums);

SELECT COUNT(*) AS total_views
FROM topic_views
WHERE topic_id = 0;

SELECT COUNT(DISTINCT role_id) AS permission_count
FROM forum_permissions
WHERE can_create_topic = 1;
